heavy_cases.command:
PDOCKER_PACKAGE="${PDOCKER_PACKAGE:-io.github.ryo100794.pdocker}"; ROOTFS="${ROOTFS:?set ROOTFS to the app-visible rootfs path}"; adb shell "run-as $PDOCKER_PACKAGE sh -lc 'cd files && PDOCKER_DIRECT_TRACE_SYSCALLS=1 pdocker-runtime/docker-bin/pdocker-direct run --mode exec --rootfs $ROOTFS --workdir /work -- /bin/sh -lc "pwd; test -r /etc/passwd; stat /etc/passwd; python3 - <<PY
import os
try: os.getcwd()
except OSError as e: print(e.errno)
PY"'"
